SELECT /*+ INDEX_DESC(A PPS_CUSTOMER_IMAGE_CHK_IDX1) ORDERED USE_NL(B C)*/ SEQ, NVL(EVENT_SEQ, '-') EVENT_SEQ, NVL(A.CONTRACT_NUM, '-') CONTRACT_NUM, NVL(SUBSCRIBER_NO, '-') SUBSCRIBER_NO, NVL(DECODE(MNP_IND_CD, '', '신규', '이동'), '-') MNP_IND_CD_NM, NVL(SUBSTR(LST_COM_ACTV_DATE, 1, 4) || '-' || SUBSTR(LST_COM_ACTV_DATE, 5, 2) || '-' || SUBSTR(LST_COM_ACTV_DATE, 7), '-') LST_COM_ACTV_DATE, NVL(AGENT_ID, '-') AGENT_ID, NVL(F_GET_AGENT_NM(AGENT_ID), '-') AGENT_NM, NVL(TO_CHAR(REG_DT, 'YYYY-MM-DD'), '-') REG_DT, NVL(CHK_STATUS, '-') CHK_STATUS, NVL(F_GET_KT_CODE_NM('PPS_CUSTOMER_IMAGE_CHK', 'CHK_STATUS', CHK_STATUS), '-') CHK_STATUS_NM, NVL((SELECT COUNT(*) FROM PPS_CUSTOMER_IMAGE WHERE IMG_GUBUN IN ('10', '11', '12') AND STATUS = 'A' AND CONTRACT_NUM = A.CONTRACT_NUM), 0) IMG_OPEN_CNT, NVL((SELECT COUNT(*) FROM PPS_CUSTOMER_IMAGE WHERE IMG_GUBUN IN ('20', '21', '22', '23', '24') AND STATUS = 'A' AND CONTRACT_NUM = A.CONTRACT_NUM), 0) IMG_ID_CNT, NVL((SELECT COUNT(*) FROM PPS_CUSTOMER_IMAGE WHERE IMG_GUBUN NOT IN ('10', '11', '12', '20', '21', '22', '23', '24') AND STATUS = 'A' AND CONTRACT_NUM = A.CONTRACT_NUM), 0) IMG_ETC_CNT, NVL(DECODE(SUBSTR(CHK_MANTY, INSTR(CHK_MANTY, '|D') + 2, 1), '0', '검수', '1', '미비', '2', '없음', '없음'), '-') D_STR, NVL(DECODE(SUBSTR(CHK_MANTY, INSTR(CHK_MANTY, '|I') + 2, 1), '0', '검수', '1', '미비', '2', '없음', '없음'), '-') I_STR, NVL(DECODE(SUBSTR(CHK_MANTY, INSTR(CHK_MANTY, '|E') + 2, 1), '0', '검수', '1', '미비', '2', '없음', '없음'), '-') E_STR, NVL(DECODE(SUBSTR(CHK_MANTY, INSTR(CHK_MANTY, '|S') + 2, 1), '0', '검수', '1', '미비', '2', '없음', '없음'), '-') S_STR, NVL(MEMO1, '-') MEMO1, NVL(DECODE(MEMO1, '', 'N', 'Y'), '-') MEMO1_FLAG, NVL(REG_ADMIN_ID, '-') REG_ADMIN_ID, NVL(F_GET_ADMIN_NM(REG_ADMIN_ID), '-') REG_ADMIN_NM, NVL(CHK_ADMIN_ID, '-') CHK_ADMIN_ID, NVL(F_GET_ADMIN_NM(CHK_ADMIN_ID), '-') CHK_ADMIN_NM, NVL(TO_CHAR(CHK_DATE, 'YYYY-MM-DD'), '-') CHK_DATE FROM PPS_CUSTOMER_IMAGE_CHK A, MSP_JUO_SUB_INFO B, PPS_CUSTOMER C WHERE A.CONTRACT_NUM = B.CONTRACT_NUM AND A.CONTRACT_NUM = C.CONTRACT_NUM
AND REG_DT >= TO_DATE(#{startDt}, 'YYYY-MM-DD')
AND REG_DT < TO_DATE(#{endDt}, 'YYYY-MM-DD')+1
AND A.CONTRACT_NUM = (select F_GET_LIKE_CTN2_CONTRACT_NUM(#{searchNm}) from dual)
AND A.CONTRACT_NUM = #{searchNm}
AND A.EVENT_SEQ = #{searchNm}
AND CHK_STATUS = #{searchChkStatus}
AND AGENT_ID = #{searchAgentId}
AND CHK_STATUS IN ('20', '21')
AND CHK_STATUS NOT IN ('00')

{CALL P_CUSTOMER_IMAGE_CHK_REG(
			    #{eventCd, jdbcType=VARCHAR}
			    , #{startDt, jdbcType=VARCHAR}
			    , #{endDt, jdbcType=VARCHAR}
			    , #{option, jdbcType=VARCHAR}
			    , #{adminId, jdbcType=VARCHAR}
			    , #{accessIp, jdbcType=VARCHAR}
			   , #{oRetCd, mode=OUT, javaType=string, jdbcType=VARCHAR}
			   , #{oRetMsg, mode=OUT, javaType=string, jdbcType=VARCHAR}
			  )
     }

{CALL P_CUSTOMER_IMAGE_CHK_CHG(
				#{opCode, jdbcType=VARCHAR}
