			  )
     }

SELECT /*+ INDEX_DESC(A PPS_AGENT_CMS_REQ_IDX1) */ SEQ, CONTRACT_NUM, STATUS, F_GET_KT_CODE_NM('PPS_AGENT_CMS_REQ', 'STATUS', STATUS) STATUS_NM, CMS_CHARGE_TYPE, F_GET_KT_CODE_NM('PPS_CUSTOMER', 'CMS_CHARGE_TYPE', CMS_CHARGE_TYPE) CMS_CHARGE_TYPE_NM, CMS_BANK_CODE, F_GET_KT_CODE_NM('PPS_RCG_REAL_CMS', 'BANK_CODE', CMS_BANK_CODE) CMS_BANK_CODE_NM, CMS_CHARGE, CMS_TRY_REMAINS, CASE WHEN CMS_CHARGE_DATE IS NOT NULL AND CMS_CHARGE_DATE < 0 THEN '만료일' || ABS(CMS_CHARGE_DATE) || '일전' ELSE CMS_CHARGE_DATE END CMS_CHARGE_DATE, CMS_CHARGE_MONTH, AGENT_ID, F_GET_AGENT_NM(AGENT_ID) AGENT_NM, TO_CHAR(REG_DT, 'YYYY-MM-DD HH24:MI:SS') REG_DT, MOD_ADMIN, F_GET_ADMIN_NM(MOD_ADMIN) MOD_ADMIN_NM, TO_CHAR(MOD_DT, 'YYYY-MM-DD HH24:MI:SS') MOD_DT FROM PPS_AGENT_CMS_REQ A WHERE SEQ IS NOT NULL
AND REG_DT >= TO_DATE(#{startDt}, 'YYYY-MM-DD')
AND REG_DT < TO_DATE(#{endDt}, 'YYYY-MM-DD')+1
AND STATUS = #{status}
AND CONTRACT_NUM IN (SELECT CONTRACT_NUM FROM MSP_JUO_SUB_INFO WHERE SUBSCRIBER_NO = #{searchNm})
AND CONTRACT_NUM = #{searchNm}
AND AGENT_ID = #{searchAgentId}

SELECT /*+ INDEX_DESC(A PPS_AGENT_CMS_REQ_IDX1) */ NVL(SEQ, 0), NVL(CONTRACT_NUM, '-') CONTRACT_NUM, NVL(STATUS, '-') STATUS, NVL(F_GET_KT_CODE_NM('PPS_AGENT_CMS_REQ', 'STATUS', STATUS), '-') STATUS_NM, NVL(CMS_CHARGE_TYPE, '-') CMS_CHARGE_TYPE, NVL(F_GET_KT_CODE_NM('PPS_CUSTOMER', 'CMS_CHARGE_TYPE', CMS_CHARGE_TYPE), '-') CMS_CHARGE_TYPE_NM, NVL(CMS_BANK_CODE, '-') CMS_BANK_CODE, NVL(F_GET_KT_CODE_NM('PPS_RCG_REAL_CMS', 'BANK_CODE', CMS_BANK_CODE), '-') CMS_BANK_CODE_NM, NVL(CMS_CHARGE, 0) CMS_CHARGE, NVL(CMS_TRY_REMAINS, 0) CMS_TRY_REMAINS, NVL(CASE WHEN CMS_CHARGE_DATE IS NOT NULL AND CMS_CHARGE_DATE < 0 THEN '만료일' || ABS(CMS_CHARGE_DATE) || '일전' ELSE CMS_CHARGE_DATE END, '-') CMS_CHARGE_DATE, NVL(CMS_CHARGE_MONTH, 0) CMS_CHARGE_MONTH, NVL(AGENT_ID, '-') AGENT_ID, NVL(F_GET_AGENT_NM(AGENT_ID), '-') AGENT_NM, NVL(TO_CHAR(REG_DT, 'YYYY-MM-DD HH24:MI:SS'), '-') REG_DT, NVL(MOD_ADMIN, '-') MOD_ADMIN, NVL(F_GET_ADMIN_NM(MOD_ADMIN), '-') MOD_ADMIN_NM, NVL(TO_CHAR(MOD_DT, 'YYYY-MM-DD HH24:MI:SS'), '-') MOD_DT FROM PPS_AGENT_CMS_REQ A WHERE SEQ IS NOT NULL
AND REG_DT >= TO_DATE(#{startDt}, 'YYYY-MM-DD')
AND REG_DT < TO_DATE(#{endDt}, 'YYYY-MM-DD')+1
AND STATUS = #{status}
AND CONTRACT_NUM IN (SELECT CONTRACT_NUM FROM MSP_JUO_SUB_INFO WHERE SUBSCRIBER_NO = #{searchNm})
AND CONTRACT_NUM = #{searchNm}
AND AGENT_ID = #{searchAgentId}

{CALL P_AGENT_CMS_REQ(
			    #{opCode, jdbcType=VARCHAR}
			    , #{seq, jdbcType=VARCHAR}
			    , #{contractNum, jdbcType=VARCHAR}
			    , #{cmsChargeType, jdbcType=VARCHAR}
			    , #{cmsBankCode, jdbcType=VARCHAR}
			    , #{cmsAccount, jdbcType=VARCHAR}
			    , #{cmsCharge, jdbcType=VARCHAR}
			    , #{cmsTryRemains, jdbcType=VARCHAR}
			    , #{cmsChargeDate, jdbcType=VARCHAR}
			    , #{cmsChargeMonth, jdbcType=VARCHAR}
			    , #{status, jdbcType=VARCHAR}
			    , #{adminMemo, jdbcType=VARCHAR}
			    , #{regTypePop, jdbcType=VARCHAR}
			   	, #{fileType, jdbcType=VARCHAR}
			   	, #{fileLen, jdbcType=VARCHAR}
			   	, #{filePath, jdbcType=VARCHAR}
			   	, #{fileEnc, jdbcType=CLOB}
			    , #{agentId, jdbcType=VARCHAR}
			    , #{adminId, jdbcType=VARCHAR} 
			   , #{oRetCd, mode=OUT, javaType=string, jdbcType=VARCHAR}
			   , #{oRetMsg, mode=OUT, javaType=string, jdbcType=VARCHAR}
			  )
     }
